import{_ as n,c as e,o as s,ag as t}from"./chunks/framework.dvv-DFtf.js";const c=JSON.parse('{"title":"GuShen — AI 量化交易平台","description":"","frontmatter":{},"headers":[],"relativePath":"gushen/index.md","filePath":"gushen/index.md","lastUpdated":null}'),i={name:"gushen/index.md"};function l(o,a,r,p,h,u){return s(),e("div",null,[...a[0]||(a[0]=[t(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /gushen.md for this page in Markdown format</div><h1 id="gushen-—-ai-量化交易平台" tabindex="-1">GuShen — AI 量化交易平台 <a class="header-anchor" href="#gushen-—-ai-量化交易平台" aria-label="Permalink to &quot;GuShen — AI 量化交易平台&quot;">​</a></h1><h2 id="什么是-gushen" tabindex="-1">什么是 GuShen？ <a class="header-anchor" href="#什么是-gushen" aria-label="Permalink to &quot;什么是 GuShen？&quot;">​</a></h2><p><strong>GuShen（股神）</strong> 是 Lurus 旗下的 AI 驱动量化交易平台。你用自然语言描述策略逻辑，平台 AI 自动生成可执行的 Python 策略代码，并支持历史回测、实时行情接入与风险控制。</p><ul><li>平台地址：<a href="https://gushen.lurus.cn" target="_blank" rel="noreferrer">gushen.lurus.cn</a></li><li>支持市场：A 股（沪深）、期货、加密货币</li></ul><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="🤖-ai-策略生成" tabindex="-1">🤖 AI 策略生成 <a class="header-anchor" href="#🤖-ai-策略生成" aria-label="Permalink to &quot;🤖 AI 策略生成&quot;">​</a></h3><p>用中文描述你的交易思路，AI 自动生成可执行的量化策略代码：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入：&quot;当 RSI 低于 30 时买入，高于 70 时卖出，仓位 50%&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>↓ AI 生成 ↓</span></span>
<span class="line"><span></span></span>
<span class="line"><span>def strategy(context):</span></span>
<span class="line"><span>    rsi = context.ta.rsi(period=14)</span></span>
<span class="line"><span>    pos = context.portfolio.positions.get(&quot;000001.SZ&quot;)</span></span>
<span class="line"><span>    if rsi[-1] &lt; 30 and not pos:</span></span>
<span class="line"><span>        context.order_percent(&quot;000001.SZ&quot;, 0.5)</span></span>
<span class="line"><span>    elif rsi[-1] &gt; 70 and pos:</span></span>
<span class="line"><span>        context.order_percent(&quot;000001.SZ&quot;, 0)</span></span></code></pre></div><h3 id="📊-历史回测" tabindex="-1">📊 历史回测 <a class="header-anchor" href="#📊-历史回测" aria-label="Permalink to &quot;📊 历史回测&quot;">​</a></h3><ul><li>支持任意时间段回测（最早 2010 年）</li><li>输出收益曲线、最大回撤、夏普比率、胜率等核心指标</li><li>与沪深 300、中证 500 等基准对比</li></ul><h3 id="📡-实时行情" tabindex="-1">📡 实时行情 <a class="header-anchor" href="#📡-实时行情" aria-label="Permalink to &quot;📡 实时行情&quot;">​</a></h3><ul><li>接入 Level-1 行情数据（1 分钟最小粒度）</li><li>支持分钟线、日线、周线等多周期数据</li><li>实时推送到策略 <code>context</code> 对象</li></ul><h3 id="🛡️-风险控制" tabindex="-1">🛡️ 风险控制 <a class="header-anchor" href="#🛡️-风险控制" aria-label="Permalink to &quot;🛡️ 风险控制&quot;">​</a></h3><ul><li>单笔最大仓位限制</li><li>单日最大亏损止损</li><li>持仓集中度告警</li></ul><h2 id="工作流程" tabindex="-1">工作流程 <a class="header-anchor" href="#工作流程" aria-label="Permalink to &quot;工作流程&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 注册/登录 → gushen.lurus.cn</span></span>
<span class="line"><span>2. 创建策略 → 自然语言输入 → AI 生成代码</span></span>
<span class="line"><span>3. 调整参数 → 历史回测验证</span></span>
<span class="line"><span>4. 满意后 → 开启模拟盘 / 实盘跟踪</span></span></code></pre></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/gushen/quickstart">快速开始</a> — 5 分钟创建你的第一个策略</li><li><a href="/gushen/strategy">策略编写指南</a> — 深入了解策略 API</li><li><a href="/gushen/api">API 参考</a> — 完整的 context 对象文档</li></ul>`,19)])])}const g=n(i,[["render",l]]);export{c as __pageData,g as default};
